import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        int bufferSize = Math.min(name.length(), 10);

        // Creating a buffer with dynamic size based on input length
        char[] buffer = new char[bufferSize];

        // Copying the user input into the buffer safely
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Welcome, " + new String(buffer));
    }
}

